class tenets_Page1 extends TabbedPage
{
	 protected function populateForm()
	{
		$this->addTabs();
		$fs = $this->form->addElement('fieldset')->setLabel('tenets page 1');
		$buttonGroup = $fs->addElement('group'); 
		$buttonGroup->addElement('submit', $this->getButtonName('back'), array('value' => '<< Back')); 
		$buttonGroup->addElement('submit', $this->getButtonName('submit'), array('value' => 'Finish')); 
		$buttonGroup->addElement('submit', $this->getButtonName('next'), array('value' => 'Next >>')); 
		$this->setDefaultAction('submit', 'empty.gif');
		$this->addGlobalSubmit();
		$idtenets = $fs->addElement('text', 'idtenets', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'Index' )
;
		$simple = $fs->addElement('text', 'simple', array('size' => 45, 'maxlength' => 45) )
			->setLabel( 'Simple Business' )
			->addRule('required', 'simple Field Required' );
		$consistent = $fs->addElement('text', 'consistent', array('size' => 45, 'maxlength' => 45) )
			->setLabel( 'Consistent Performance' )
			->addRule('required', 'consistent Field Required' );
		$longterm = $fs->addElement('text', 'longterm', array('size' => 45, 'maxlength' => 45) )
			->setLabel( 'Long Term Prospects' )
			->addRule('required', 'longterm Field Required' );
		$rationalmanager = $fs->addElement('text', 'rationalmanager', array('size' => 45, 'maxlength' => 45) )
			->setLabel( 'Rational Management' )
			->addRule('required', 'rationalmanager Field Required' );
		$candid = $fs->addElement('text', 'candid', array('size' => 45, 'maxlength' => 45) )
			->setLabel( 'Candid with Shareholders' )
			->addRule('required', 'candid Field Required' );
		$resistinstitution = $fs->addElement('text', 'resistinstitution', array('size' => 45, 'maxlength' => 45) )
			->setLabel( 'Management resists the Institution' )
			->addRule('required', 'resistinstitution Field Required' );
		$focusroe = $fs->addElement('text', 'focusroe', array('size' => 45, 'maxlength' => 45) )
			->setLabel( 'Focus on Return on Equity, not EPS' )
			->addRule('required', 'focusroe Field Required' );
		$ownerearnings = $fs->addElement('text', 'ownerearnings', array('size' => 45, 'maxlength' => 45) )
			->setLabel( 'Calculated Owner Earnings' )
			->addRule('required', 'ownerearnings Field Required' );
		$highprofitmargin = $fs->addElement('text', 'highprofitmargin', array('size' => 45, 'maxlength' => 45) )
			->setLabel( 'High Profit Margins' )
			->addRule('required', 'highprofitmargin Field Required' );
		$retainedtomarket = $fs->addElement('text', 'retainedtomarket', array('size' => 45, 'maxlength' => 45) )
			->setLabel( 'Retained Earnings become Market Value' )
			->addRule('required', 'retainedtomarket Field Required' );
		$valueofbusiness = $fs->addElement('text', 'valueofbusiness', array('size' => 45, 'maxlength' => 45) )
			->setLabel( 'Value of Business' )
			->addRule('required', 'valueofbusiness Field Required' );
		$discounted = $fs->addElement('text', 'discounted', array('size' => 45, 'maxlength' => 45) )
